parameters.jsCode:
const w = $('Slash Command Webhook').first().json;
const b = w.body || w;
function f(n) { return String(b[n] || w[n] || ''); }
const text = f('text').trim().toLowerCase();
let sub = 'digest', args = text;
if (text.startsWith('help')) sub = 'help';
else if (text.startsWith('calibrate')) { sub = 'calibrate'; args = ''; }
else if (text.startsWith('target')) { sub = 'targets'; args = ''; }
const region = sub === 'digest' ? args.replace(/\w\S*/g, w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()) : '';
return [{ json: { userId: f('user_id'), userName: f('user_name'), channelId: f('channel_id'), responseUrl: f('response_url'), teamDomain: f('team_domain'), subcommand: sub, sales_region: region } }];

const csvData = $json.data || '';
if (!csvData.trim()) return [{ json: { _empty: true, neglected: [], surging: [], expansion: [] } }];

function parseCSVLine(line) {
  const vals = []; let inQ = false, cur = '';
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { inQ = !inQ; continue; }
    if (c === ',' && !inQ) { vals.push(cur.trim()); cur = ''; continue; }
    cur += c;
  }
  vals.push(cur.trim());
  return vals;
}

const lines = csvData.trim().split('\n');
const headers = parseCSVLine(lines[0]);
console.log('Headers:', headers.join(' | '));

const accounts = [];
for (let i = 1; i < lines.length; i++) {
  const vals = parseCSVLine(lines[i]);
  if (vals.length < 3) continue;
  const acc = {};
  headers.forEach((h, idx) => acc[h] = vals[idx] || '');
  accounts.push(acc);
}

const toNum = s => { const n = Number(String(s || '0').replace(/[,$]/g, '')); return isFinite(n) ? n : 0; };

const enriched = accounts.map(a => ({
  name: a['Account Name'] || 'Unknown',
  owner: a['Account Owner (name)'] || a['Account Owner (id)'] || 'Unassigned',
  engagement: toNum(a['Account Engagement Level']),
  meetings: toNum(a['Meetings (Last 30 Days)']),
  emailsSent: toNum(a['Emails Sent (Last 30 Days)']),
  emailsRecv: toNum(a['Emails Received (Last 30 Days)']),
  people: toNum(a['People Engaged (Last 30 Days)']),
  execs: toNum(a['Executives Engaged (Last 30 Days)']),
  execActs: toNum(a['Activities with Executives (C-Level) (Last 30 Days)']),
  revenue: a['Annual Revenue'] || '',
  paiId: a['People.ai Internal ID'] || ''
}));

const neglected = enriched.filter(a => a.engagement <= 40 && a.meetings <= 2)
  .sort((a, b) => toNum(b.revenue) - toNum(a.revenue)).slice(0, 10);

const surging = enriched.filter(a => a.engagement >= 70)
  .sort((a, b) => b.engagement - a.engagement || b.meetings - a.meetings).slice(0, 10);

const expansion = enriched.filter(a => a.engagement >= 50 && a.people >= 3 && a.execs >= 1)
  .sort((a, b) => b.engagement - a.engagement).slice(0, 10);

console.log('Parsed ' + accounts.length + ': ' + neglected.length + ' neglected, ' + surging.length + ' surging, ' + expansion.length + ' expansion');
return [{ json: { totalAccounts: accounts.length, neglected, surging, expansion } }];

const d = $json;
const cmd = $('Extract Command').first().json;
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

function fmtList(items) {
  if (!items || items.length === 0) return '_No accounts found matching criteria._';
  return items.map((a, i) => {
    const emails = a.emailsSent + a.emailsRecv;
    const link = a.paiId ? '<https://app.people.ai/account/' + a.paiId + '|' + a.name + '>' : '*' + a.name + '*';
    return (i+1) + '. ' + link + ' (' + a.owner + ')\n' +
      '    Eng: ' + a.engagement + ' | Mtgs: ' + a.meetings + ' | Emails: ' + emails +
      ' | People: ' + a.people + ' | Execs: ' + a.execs +
      (a.revenue ? ' | Rev: ' + a.revenue : '');
  }).join('\n');
}

const text = '\ud83c\udfe2 *Account Insights Digest*\n_' + date + '_\n\n' +
  '\ud83d\udea8 *NEGLECTED ACCOUNTS* \u2014 Low engagement, going dark\n' + fmtList(d.neglected) + '\n\n' +
  '\ud83d\udcc8 *SURGING ACCOUNTS* \u2014 Highest engagement\n' + fmtList(d.surging) + '\n\n' +
  '\ud83d\udc8e *EXPANSION CANDIDATES* \u2014 Broad engagement with exec access\n' + fmtList(d.expansion) + '\n\n' +
  '_' + d.totalAccounts + ' accounts analyzed \u2022 People.ai + Claude AI_';

return [{ json: { text, responseUrl: cmd.responseUrl } }];
